INSERT INTO SkillCategory (CategoryName, Description) VALUES
('Programming', 'Coding, scripting, and software development including web, desktop, and scripting languages used in industry and academia'),
('Languages', 'Spoken and written language learning for communication, academic writing, and professional use in multilingual settings'),
('Design', 'Graphic design, visual communication, UI/UX design, and creative tools for digital and print media'),
('Academic', 'Subject tutoring, exam preparation, and academic support for engineering, science, and mathematics courses'),
('Music & Arts', 'Music instruments, music theory, drawing, sketching, and creative arts for beginners and hobbyists'),
('Professional', 'Resume writing, cover letters, presentations, public speaking, and interview preparation for the job market'),
('Data & Analytics', 'Data science, statistical analysis, machine learning fundamentals, and spreadsheet tools for data-driven work'),
('Engineering', 'Technical and engineering skills including simulation software, electronics, and hardware prototyping'),
('Communication', 'Professional and creative writing, content creation, and effective communication for work and study'),
('Other', 'Photography, digital marketing, project management, and other practical skills useful for students and professionals');
INSERT INTO Skill (CategoryID, SkillName, Description, DifficultyLevel) VALUES
(1, 'Python', 'Python programming from basics to data structures, scripting, and introductory data science; suitable for university projects and self-study', 'beginner'), (1, 'JavaScript', 'JavaScript and frontend development including DOM, async programming, and basic framework concepts for web applications', 'intermediate'), (1, 'SQL & Databases', 'Relational databases, SQL queries, normalization, and database design using MySQL or PostgreSQL for academic and small projects', 'intermediate'),
(2, 'English', 'Spoken and written English for daily conversation, academic writing, and professional communication including email and presentations', 'beginner'), (2, 'Urdu', 'Urdu language reading, writing, and formal communication; suitable for essays, official correspondence, and cultural exchange', 'beginner'), (2, 'Arabic', 'Arabic script, basic vocabulary, and simple conversation for religious or academic purposes; beginner-friendly', 'beginner'),
(3, 'Graphic Design', 'Canva, basic design principles, and visual branding for social media, posters, and simple marketing materials', 'intermediate'), (3, 'UI/UX', 'User interface and user experience design using Figma; wireframes, prototypes, and design systems for web and mobile', 'intermediate'), (3, 'Video Editing', 'Video editing basics with common tools; cutting, transitions, subtitles, and simple effects for projects and content creation', 'intermediate'),
(4, 'Calculus', 'Calculus I and II including limits, derivatives, integrals, and applications for engineering and science students', 'intermediate'), (4, 'Linear Algebra', 'Matrices, vectors, linear transformations, and eigenvalues; applications in engineering and computer science', 'intermediate'), (4, 'Statistics', 'Descriptive and inferential statistics, hypothesis testing, and interpretation for research and data analysis', 'intermediate'),
(5, 'Guitar', 'Acoustic guitar from basic chords and strumming to simple songs; suitable for complete beginners', 'beginner'), (5, 'Piano', 'Piano basics including notes, scales, and simple pieces for hobbyists and beginners', 'beginner'), (5, 'Sketching', 'Pencil sketching, shading, and basic composition for drawing and visual note-taking', 'beginner'),
(6, 'Resume Writing', 'CV and cover letter writing tailored to the Pakistani job market; structure, keywords, and formatting', 'beginner'), (6, 'Public Speaking', 'Presentation skills, confidence building, and effective delivery for academic and professional settings', 'intermediate'), (6, 'Interview Prep', 'Technical and behavioral interview preparation including common questions and communication tips', 'intermediate'),
(7, 'Data Analysis', 'Data analysis using Excel and Python; cleaning, visualization, and basic interpretation for reports and projects', 'intermediate'), (7, 'Machine Learning', 'Introduction to machine learning concepts, common algorithms, and basic implementation with Python libraries', 'advanced'), (7, 'Excel', 'Microsoft Excel including formulas, pivot tables, charts, and data management for academic and office use', 'beginner'),
